    padding:12px;
    display:flex;
    align-items:center;
    justify-content:center;
  }

  .gbm-solar-qr-box img{
    width:100%;
    max-width:250px;
    aspect-ratio:1/1;
    object-fit:contain;
    display:block;
  }

  .gbm-solar-link{
    margin-top:14px;
    text-align:center;
    font-size:22px;
    line-height:1.2;
    font-weight:800;
    color:var(--solar-primary);
